# Let me try to work with the attachment more systematically
# I'll check if there are any environment variables or special paths for attachments

import os
import sys

print("Environment variables that might contain attachment info:")
for key, value in os.environ.items():
    if any(word in key.lower() for word in ['attach', 'task', 'file', 'data']):
        print(f"{key}: {value}")

print("\nPython path:")
for path in sys.path:
    print(f"  {path}")

# Check common attachment locations
common_paths = ['/tmp', '/attachments', '/task', '/data', '/input']
for path in common_paths:
    if os.path.exists(path):
        print(f"\nContents of {path}:")
        try:
            files = os.listdir(path)
            for file in files:
                print(f"  {file}")
        except PermissionError:
            print(f"  Permission denied")
        except Exception as e:
            print(f"  Error: {e}")

# Check if there are any files in common attachment directories
import os
import glob

print("Searching for files recursively...")
for root, dirs, files in os.walk('/'):
    if files:
        for file in files:
            if 'applicant' in file.lower() or 'xlsx' in file.lower() or 'job' in file.lower() or 'pdf' in file.lower():
                print(f"Found relevant file: {os.path.join(root, file)}")

# Also check if there are any hidden or temporary files
print("\nChecking for zip or Excel files in common locations:")
common_patterns = ['*.zip', '*.xlsx', '*.pdf', '*applicant*', '*job*']
for pattern in common_patterns:
    matches = glob.glob(pattern, recursive=True)
    if matches:
        print(f"Pattern {pattern}: {matches}")

# Check /tmp directory specifically
print("\nChecking /tmp directory:")
if os.path.exists('/tmp'):
    print(os.listdir('/tmp'))
